// Server maintains the set of active clients and broadcasts messages to them.
type Server struct {
	clients    map[*Client]bool       // Registered clients.
	broadcast  chan []byte            // Inbound messages from the clients.
	register   chan *Client           // Register requests from the clients.
	unregister chan *Client           // Unregister requests from clients.
	commands   map[string]Command     // Registered admin commands.
	mu         sync.RWMutex           // Mutex to protect clients map.
	userMap    map[string]*Client     // Map username to client for easier lookup
	idMap      map[string]*Client     // Map ID to client
}

// NewServer creates and returns a new Server instance.
func NewServer() *Server {
	s := &Server{
		clients:    make(map[*Client]bool),
		broadcast:  make(chan []byte),
		register:   make(chan *Client),
		unregister: make(chan *Client),
		commands:   make(map[string]Command),
		userMap:    make(map[string]*Client),
		idMap:      make(map[string]*Client),
	}
	s.registerCommands()
	return s
}

// Run starts the server's event loop.
func (s *Server) Run() {
	for {
		select {
		case client := <-s.register:
			s.mu.Lock()
			s.clients[client] = true
			s.userMap[client.Username] = client
			s.idMap[client.ID] = client
			s.mu.Unlock()
			log.Printf("Client registered: %s (ID: %s, Roles: %v)", client.Username, client.ID, client.Roles)
			client.Send <- []byte(fmt.Sprintf("Welcome, %s! You are connected.", client.Username))
			s.broadcast <- []byte(fmt.Sprintf("%s has joined the chat.", client.Username))

		case client := <-s.unregister:
			s.mu.Lock()
			if _, ok := s.clients[client]; ok {
				delete(s.clients, client)
				delete(s.userMap, client.Username)
				delete(s.idMap, client.ID)
				close(client.Send)
				log.Printf("Client unregistered: %s (ID: %s)", client.Username, client.ID)
				s.broadcast <- []byte(fmt.Sprintf("%s has left the chat.", client.Username))
			}
			s.mu.Unlock()

		case message := <-s.broadcast:
			s.mu.RLock()
			for client := range s.clients {
				select {
				case client.Send <- message:
				default:
					// If client.Send is blocked, assume client is gone.
					close(client.Send)
					delete(s.clients, client)
					delete(s.userMap, client.Username)
					delete(s.idMap, client.ID)
				}
			}
			s.mu.RUnlock()
		}
	}
}

