// hasRole checks if a client has any of the required roles.
func (c *Client) hasRole(requiredRoles []string) bool {
	if len(requiredRoles) == 0 {
		return true // No roles required, anyone can execute
	}
	for _, role := range requiredRoles {
		if c.Roles[role] {
			return true
		}
	}
	return false
}

// handleCommand parses and executes an admin command.
func (s *Server) handleCommand(sender *Client, message string) {
	parts := strings.Fields(message)
	if len(parts) == 0 {
		sender.Send <- []byte("Error: Empty command.")
		return
	}

	cmdName := strings.TrimPrefix(parts[0], "/")
	args := parts[1:]

	cmd, exists := s.commands[cmdName]
	if !exists {
		sender.Send <- []byte(fmt.Sprintf("Error: Unknown command '%s'. Type /help for a list of commands.", cmdName))
		return
	}

	if !sender.hasRole(cmd.RequiredRoles) {
		sender.Send <- []byte(fmt.Sprintf("Error: You do not have permission to use the '%s' command. Required roles: %v", cmdName, cmd.RequiredRoles))
		return
	}

	if err := cmd.Handler(sender, args); err != nil {
		sender.Send <- []byte(fmt.Sprintf("Command '%s' failed: %v", cmdName, err))
	} else {
		// Command executed successfully, handler should send specific feedback if needed
	}
}

